use unicode_segmentation::UnicodeSegmentation;
use super::*;

// === Grapheme helpers ===

fn prev_grapheme_boundary(s: &str, pos: usize) -> usize {
    let mut last = 0;
    for (i, _) in s.grapheme_indices(true) {
        if i >= pos { break; }
        last = i;
    }
    last
}

fn next_grapheme_boundary(s: &str, pos: usize) -> usize {
    for (i, _) in s.grapheme_indices(true) {
        if i > pos { return i; }
    }
    s.len()
}

// === Word boundary helpers ===

fn find_word_boundary_left(s: &str, pos: usize) -> usize {
    let mut pos = pos;
    while pos > 0 {
        let prev = prev_grapheme_boundary(s, pos);
        if &s[prev..pos] != " " { break; }
        pos = prev;
    }
    while pos > 0 {
        let prev = prev_grapheme_boundary(s, pos);
        if &s[prev..pos] == " " { break; }
        pos = prev;
    }
    pos
}

fn find_word_boundary_right(s: &str, pos: usize) -> usize {
    let mut pos = pos;
    let len = s.len();
    while pos < len {
        let next = next_grapheme_boundary(s, pos);
        if &s[pos..next] == " " { break; }
        pos = next;
    }
    while pos < len {
        let next = next_grapheme_boundary(s, pos);
        if &s[pos..next] != " " { break; }
        pos = next;
    }
    pos
}

impl AppState {
    pub fn hint_text(&self) -> String {
        let mut parts = Vec::new();
        parts.push("Ctrl+Shift+E=expand/collapse".to_string());
        if self.at_suggestions.is_some() {
            parts.push("Tab=cycle".to_string());
            parts.push("Enter=insert".to_string());
            parts.push("Esc=close".to_string());
        } else if self.turn_active {
            parts.push("Enter=steer".to_string());
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=abort".to_string());
        } else if !self.input.is_empty() {
            parts.push("Enter=send".to_string());
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=clear".to_string());
        } else {
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=clear".to_string());
        }
        parts.push("Ctrl+C=quit".to_string());
        parts.join(" | ")
    }

    // === Cursor Movement (grapheme-aware) ===

    pub(crate) fn cursor_left(&mut self) {
        if self.cursor_pos > 0 {
            self.cursor_pos = prev_grapheme_boundary(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_right(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.cursor_pos = next_grapheme_boundary(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_start(&mut self) {
        if self.input.contains('\n') {
            self.move_cursor_to_line_start();
        } else if self.cursor_pos != 0 {
            self.cursor_pos = 0;
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_end(&mut self) {
        if self.input.contains('\n') {
            self.move_cursor_to_line_end();
        } else if self.cursor_pos != self.input.len() {
            self.cursor_pos = self.input.len();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Word Navigation ===

    pub(crate) fn cursor_word_left(&mut self) {
        if self.cursor_pos > 0 {
            self.cursor_pos = find_word_boundary_left(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_word_right(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.cursor_pos = find_word_boundary_right(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Text Editing ===

    pub(crate) fn insert_char(&mut self, c: char) {
        self.push_undo();
        if self.cursor_pos == self.input.len() {
            self.input.push(c);
        } else {
            self.input.insert(self.cursor_pos, c);
        }
        self.cursor_pos += c.len_utf8();
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    pub(crate) fn delete_before_cursor(&mut self) {
        if self.cursor_pos > 0 {
            // Check if the character before cursor is a newline
            let char_before_cursor = self.input[..self.cursor_pos].chars().last();
            if char_before_cursor == Some('\n') {
                // Remove the newline character (join lines)
                self.push_undo();
                let new_pos = self.cursor_pos - 1; // Position after removing newline
                self.input.remove(self.cursor_pos - 1);
                self.cursor_pos = new_pos;
                self.clear_redo();
                self.handle_at_trigger();
                self.mark_dirty();
            } else {
                // Normal delete - remove grapheme before cursor
                self.push_undo();
                let new_pos = prev_grapheme_boundary(&self.input, self.cursor_pos);
                self.input.drain(new_pos..self.cursor_pos);
                self.cursor_pos = new_pos;
                self.clear_redo();
                self.handle_at_trigger();
                self.mark_dirty();
            }
        } else if self.cursor_pos == 0 && !self.input.is_empty() {
            // Cursor at absolute start - check if there's a newline
            if self.input.starts_with('\n') {
                self.push_undo();
                self.input.remove(0);
                self.clear_redo();
                self.handle_at_trigger();
                self.mark_dirty();
            } else {
                self.input_flash = 3;
            }
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn delete_word(&mut self) {
        if self.cursor_pos == 0 {
            self.input_flash = 3;
            return;
        }
        self.push_undo();
        let start = find_word_boundary_left(&self.input, self.cursor_pos);
        self.input.drain(start..self.cursor_pos);
        self.cursor_pos = start;
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    pub(crate) fn delete_to_end(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.push_undo();
            self.input.truncate(self.cursor_pos);
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn delete_to_start(&mut self) {
        if self.cursor_pos > 0 {
            self.push_undo();
            self.input.drain(..self.cursor_pos);
            self.cursor_pos = 0;
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn kill_char(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.push_undo();
            let end = next_grapheme_boundary(&self.input, self.cursor_pos);
            self.input.drain(self.cursor_pos..end);
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Undo / Redo ===

    fn push_undo(&mut self) {
        self.undo_stack.push((self.input.clone(), self.cursor_pos));
    }

    fn clear_redo(&mut self) {
        self.redo_stack.clear();
    }

    pub(crate) fn undo(&mut self) {
        if let Some((text, pos)) = self.undo_stack.pop() {
            self.redo_stack.push((self.input.clone(), self.cursor_pos));
            self.input = text;
            self.cursor_pos = pos;
            self.handle_at_trigger();
            self.mark_dirty();
        }
    }

    pub(crate) fn redo(&mut self) {
        if let Some((text, pos)) = self.redo_stack.pop() {
            self.undo_stack.push((self.input.clone(), self.cursor_pos));
            self.input = text;
            self.cursor_pos = pos;
            self.handle_at_trigger();
            self.mark_dirty();
        }
    }

    // === Paste ===

    pub(crate) fn paste(&mut self, text: &str) {
        let clean = text
            .replace("\r\n", "")
            .replace(['\r', '\n'], "")
            .replace('\t', "    ");
        if clean.is_empty() {
            return;
        }
        self.push_undo();
        self.input.insert_str(self.cursor_pos, &clean);
        self.cursor_pos += clean.len();
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    // === Legacy methods ===

    pub(crate) fn push_input(&mut self, c: char) {
        if c == '\t' {
            if self.input.contains('@') || self.at_suggestions.is_some() {
                self.cycle_at_suggestions();
            }
            return;
        }
        self.insert_char(c);
    }

    pub(crate) fn pop_input(&mut self) {
        self.delete_before_cursor();
    }

    pub(crate) fn insert_newline(&mut self) {
        self.push_undo();
        if self.cursor_pos == self.input.len() {
            self.input.push('\n');
        } else {
            self.input.insert(self.cursor_pos, '\n');
        }
        self.cursor_pos += 1;
        self.clear_redo();
        self.mark_dirty();
    }

    pub(crate) fn submit(&mut self) {
        if self.at_suggestions.is_some() {
            self.insert_at_suggestion();
            return;
        }
        if self.input.is_empty() {
            self.input_flash = 3;
            return;
        }
        let content = std::mem::take(&mut self.input).trim().to_string();
        self.cursor_pos = 0;
        self.history_pos = None;
        self.undo_stack.clear();
        self.redo_stack.clear();
        if content.is_empty() {
            return;
        }

        // Handle bash prefix (!)
        if content.starts_with('!') {
            let command = content[1..].trim().to_string();
            if !command.is_empty() {
                self.run_bash_command(&command);
            }
            return;
        }

        self.input_history.push(content.clone());
        if let Some(response) = self.handle_slash(&content) {
            self.add_system_msg(response);
            return;
        }
        if self.turn_active {
            self.message_queue.push(crate::model::QueuedMessage {
                content,
                kind: crate::model::QueuedMessageKind::Steering,
            });
            self.scroll = 0;
            self.mark_dirty();
            return;
        }
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((content, id));
        self.scroll = 0;
        self.messages_changed();
    }

    /// Run a bash command and display output
    fn run_bash_command(&mut self, command: &str) {
        let result = bash::execute_bash(command);
        let output_msg = format!("$ {}\n{}", command, result);
        self.add_system_msg(output_msg);
        self.scroll = 0;
        self.messages_changed();
    }

    // === Input History ===

    pub(crate) fn history_prev(&mut self) {
        if self.input_history.is_empty() {
            self.input_flash = 3;
            return;
        }
        let pos = match self.history_pos {
            Some(p) if p > 0 => p - 1,
            Some(p) => p,
            None => self.input_history.len() - 1,
        };
        self.history_pos = Some(pos);
        self.input = self.input_history[pos].clone();
        self.cursor_pos = self.input.len();
        self.mark_dirty();
    }

    pub(crate) fn history_next(&mut self) {
        let pos = match self.history_pos {
            Some(p) => p + 1,
            None => {
                self.input_flash = 3;
                return;
            }
        };
        if pos >= self.input_history.len() {
            self.history_pos = None;
            self.input.clear();
            self.cursor_pos = 0;
        } else {
            self.history_pos = Some(pos);
            self.input = self.input_history[pos].clone();
            self.cursor_pos = self.input.len();
        }
        self.mark_dirty();
    }

    // === @-ref suggestions ===

    fn handle_at_trigger(&mut self) {
        if self.input.contains('@') {
            let query = self.input.split('@').next_back().unwrap_or("").to_string();
            let needs_refresh = self.last_at_query.as_ref() != Some(&query)
                || self.at_suggestions.is_none();
            if needs_refresh {
                self.last_at_query = Some(query.clone());
                self.refresh_at_suggestions();
            }
        } else {
            self.at_suggestions = None;
            self.at_selected = None;
            self.last_at_query = None;
        }
    }

    fn refresh_at_suggestions(&mut self) {
        let query = self.input.split('@').next_back().unwrap_or("").to_string();
        let mut suggestions = crate::file_refs::complete_at_ref(&self.input, ".", 50);
        if suggestions.len() > 1 && !query.is_empty() {
            let refs: Vec<&str> = suggestions.iter().map(|s| s.as_str()).collect();
            suggestions = crate::fuzzy::fuzzy_filter(&query, &refs, 10)
                .into_iter()
                .map(|s| s.to_string())
                .collect();
        }
        if suggestions.is_empty() {
            suggestions = crate::file_refs::find_files("", ".", 10);
        }
        if suggestions.is_empty() {
            self.at_suggestions = None;
            self.at_selected = None;
            return;
        }
        self.at_suggestions = Some(suggestions);
        self.at_selected = Some(0);
        self.mark_dirty();
    }

    fn cycle_at_suggestions(&mut self) {
        if let Some(suggestions) = self.at_suggestions.as_mut() {
            let idx = self.at_selected.map(|i| (i + 1) % suggestions.len()).unwrap_or(0);
            self.at_selected = Some(idx);
            self.mark_dirty();
        } else {
            self.refresh_at_suggestions();
        }
    }

    fn insert_at_suggestion(&mut self) {
        if let Some(idx) = self.at_selected {
            if let Some(suggestions) = self.at_suggestions.take() {
                if let Some(selected) = suggestions.get(idx) {
                    self.input = crate::file_refs::insert_at_ref(&self.input, selected);
                    self.cursor_pos = self.input.len();
                }
            }
            self.at_selected = None;
            self.last_at_query = None;
            self.mark_dirty();
        }
    }
}

//! Line navigation helpers for multi-line input

use crate::model::AppState;

impl AppState {
    /// Get the current line boundaries (start and end positions, exclusive end)
    pub(crate) fn get_current_line_bounds(&self) -> (usize, usize) {
        if self.input.is_empty() {
            return (0, 0);
        }

        // Find which line the cursor is on
        let mut current_pos = 0;
        let mut line_start = 0;
        let mut line_end = self.input.len();

        for (i, c) in self.input.char_indices() {
            if c == '\n' {
                if i >= self.cursor_pos {
                    line_end = i;
                    break;
                }
                line_start = i + 1;
            }
        }

        // Check if cursor is past the last newline (last line)
        if line_end == self.input.len() && self.input.ends_with('\n') {
            // Input ends with newline, last line is empty
            if self.cursor_pos > line_start {
                line_end = self.input.len();
            }
        }

        (line_start, line_end)
    }

    /// Move cursor to the start of the current line
    pub(crate) fn move_cursor_to_line_start(&mut self) {
        let (line_start, _) = self.get_current_line_bounds();
        self.cursor_pos = line_start;
        self.mark_dirty();
    }

    /// Move cursor to the end of the current line
    pub(crate) fn move_cursor_to_line_end(&mut self) {
        let (_, line_end) = self.get_current_line_bounds();
        self.cursor_pos = line_end;
        self.mark_dirty();
    }

    /// Move cursor up one line (if in multi-line mode)
    pub(crate) fn move_cursor_up(&mut self) {
        if !self.input.contains('\n') {
            // Single line - do history navigation
            self.history_prev();
            return;
        }

        let (line_start, _) = self.get_current_line_bounds();

        // Find the previous line
        if line_start == 0 {
            // Already on first line - flash
            self.input_flash = 3;
            return;
        }

        // Find start of previous line
        let prev_line_start = self.input[..line_start - 1]
            .rfind('\n')
            .map(|i| i + 1)
            .unwrap_or(0);

        // Calculate the column we're on
        let current_col = self.cursor_pos - line_start;

        // Find the previous line's end
        let prev_line_end = line_start - 1;
        let prev_line_len = prev_line_end - prev_line_start;

        // Position cursor at same column (or end of line if line is shorter)
        self.cursor_pos = prev_line_start + current_col.min(prev_line_len);
        self.mark_dirty();
    }

    /// Move cursor down one line (if in multi-line mode)
    pub(crate) fn move_cursor_down(&mut self) {
        if !self.input.contains('\n') {
            // Single line - do history navigation
            self.history_next();
            return;
        }

        let (_, line_end) = self.get_current_line_bounds();

        // Check if we're on the last line
        if line_end >= self.input.len() {
            // Already on last line - flash
            self.input_flash = 3;
            return;
        }

        // Skip the newline and find next line's start
        let next_line_start = line_end + 1;

        // Find the end of the next line
        let next_line_end = self.input[next_line_start..]
            .find('\n')
            .map(|i| next_line_start + i)
            .unwrap_or(self.input.len());

        // Calculate the column we're on
        let (current_line_start, _) = self.get_current_line_bounds();
        let current_col = self.cursor_pos - current_line_start;

        // Position cursor at same column (or end of line if line is shorter)
        let next_line_len = next_line_end - next_line_start;
        self.cursor_pos = next_line_start + current_col.min(next_line_len);
        self.mark_dirty();
    }
}

#[cfg(test)]
mod tests {
    use crate::model::AppState;

    #[test]
    fn single_line_cursor_start_end() {
        let mut state = AppState::default();
        state.input = "hello world".to_string();
        state.cursor_pos = 5;

        state.move_cursor_to_line_start();
        assert_eq!(state.cursor_pos, 0);

        state.move_cursor_to_line_end();
        assert_eq!(state.cursor_pos, 11);
    }

    #[test]
    fn multiline_line_bounds() {
        let mut state = AppState::default();
        // "line1\nline2\nline3"
        //  01234 5  6789 10 11  1213141516
        state.input = "line1\nline2\nline3".to_string();

        // Cursor on first line (column 3)
        state.cursor_pos = 3;
        let (start, end) = state.get_current_line_bounds();
        assert_eq!(start, 0, "first line start");
        assert_eq!(end, 5, "first line end (exclusive)");

        // Cursor on second line (column 2)
        state.cursor_pos = 8;
        let (start, end) = state.get_current_line_bounds();
        assert_eq!(start, 6, "second line start");
        assert_eq!(end, 11, "second line end (exclusive)");

        // Cursor on last line (column 3)
        state.cursor_pos = 15;
        let (start, end) = state.get_current_line_bounds();
        assert_eq!(start, 12, "last line start");
        assert_eq!(end, 17, "last line end (exclusive)");
    }

    #[test]
    fn move_cursor_up_first_line_flashes() {
        let mut state = AppState::default();
        state.input = "line1\nline2".to_string();
        state.cursor_pos = 2; // On first line

        state.move_cursor_up();
        assert_eq!(state.input_flash, 3); // Flash indicator
    }

    #[test]
    fn move_cursor_up_navigates() {
        let mut state = AppState::default();
        state.input = "line1\nline2".to_string();
        state.cursor_pos = 8; // On second line (column 2)

        state.move_cursor_up();
        assert_eq!(state.cursor_pos, 2); // First line, same column
    }

    #[test]
    fn move_cursor_down_last_line_flashes() {
        let mut state = AppState::default();
        state.input = "line1\nline2".to_string();
        state.cursor_pos = 8; // On last line

        state.move_cursor_down();
        assert_eq!(state.input_flash, 3); // Flash indicator
    }

    #[test]
    fn move_cursor_down_navigates() {
        let mut state = AppState::default();
        state.input = "line1\nline2\nline3".to_string();
        state.cursor_pos = 2; // On first line (column 2)

        state.move_cursor_down();
        assert_eq!(state.cursor_pos, 8); // Second line, same column

        state.move_cursor_down();
        assert_eq!(state.cursor_pos, 14); // Third line, same column
    }

    #[test]
    fn cursor_preserves_column_when_moving() {
        let mut state = AppState::default();
        // "ab\nabcdef" - Line 0 has 2 chars, Line 1 has 6 chars
        state.input = "ab\nabcdef".to_string();
        state.cursor_pos = 6; // On second line, column 3 ('d')

        state.move_cursor_up();
        // First line has 2 chars, column 3 clamps to 2
        assert_eq!(state.cursor_pos, 2); // End of first line

        state.move_cursor_down();
        // Back to second line, column 2 ('c')
        assert_eq!(state.cursor_pos, 5);
    }

    #[test]
    fn column_clamped_to_line_length() {
        let mut state = AppState::default();
        state.input = "ab\nabcdef".to_string();
        state.cursor_pos = 10; // On second line, column 6

        state.move_cursor_up();
        // First line is shorter (2 chars), column should be clamped
        assert_eq!(state.cursor_pos, 2); // End of first line
    }
}

use crate::model::{AppState, ChatMessage, Role};
use crate::Event;

mod agent;
mod bash;
mod input;
mod line_nav;
mod queue;
mod slash;

pub(crate) fn now() -> f64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs_f64())
        .unwrap_or(0.0)
}

pub(crate) fn strip_tool_markers(content: &str) -> String {
    if let Some(pos) = content.find("TOOL:") {
        let before = &content[..pos];
        return before.trim_end().to_string();
    }
    let mut result = String::new();
    for line in content.lines() {
        let trimmed = line.trim();
        if trimmed.starts_with('{') {
            if let Ok(val) = serde_json::from_str::<serde_json::Value>(trimmed) {
                if val.get("name").is_some() && val.get("arguments").is_some() {
                    continue;
                }
            }
        }
        if !result.is_empty() {
            result.push('\n');
        }
        result.push_str(line);
    }
    result
}

pub(crate) fn content_has_tool_markers(content: &str) -> bool {
    if content.contains("TOOL:") {
        return true;
    }
    content.lines().any(|line| {
        let trimmed = line.trim();
        if !trimmed.starts_with('{') {
            return false;
        }
        serde_json::from_str::<serde_json::Value>(trimmed)
            .map(|v| v.get("name").is_some() && v.get("arguments").is_some())
            .unwrap_or(false)
    })
}

impl AppState {
    pub fn update(&mut self, event: Event) {
        match event {
            Event::Input(c) => self.push_input(c),
            Event::Backspace => self.pop_input(),
            Event::Newline => self.insert_newline(),
            Event::CursorLeft => self.cursor_left(),
            Event::CursorRight => self.cursor_right(),
            Event::CursorStart => self.cursor_start(),
            Event::CursorEnd => self.cursor_end(),
            Event::DeleteWord => self.delete_word(),
            Event::DeleteToEnd => self.delete_to_end(),
            Event::DeleteToStart => self.delete_to_start(),
            Event::KillChar => self.kill_char(),
            Event::HistoryPrev => {
                if self.input.contains('\n') {
                    self.move_cursor_up();
                } else {
                    self.history_prev();
                }
            }
            Event::HistoryNext => {
                if self.input.contains('\n') {
                    self.move_cursor_down();
                } else {
                    self.history_next();
                }
            }
            Event::Undo => self.undo(),
            Event::Redo => self.redo(),
            Event::CursorWordLeft => self.cursor_word_left(),
            Event::CursorWordRight => self.cursor_word_right(),
            Event::Paste(text) => self.paste(&text),
            Event::Submit => self.submit(),
            Event::ScrollUp => {
                if self.messages.is_empty() && !self.turn_active {
                    self.input_flash = 3;
                }
                self.scroll = self.scroll.saturating_add(1);
            }
            Event::ScrollDown => {
                if self.scroll == 0 {
                    self.input_flash = 3;
                }
                self.scroll = self.scroll.saturating_sub(1);
            }
            Event::Quit => {}
            Event::Reset => *self = AppState::default(),
            Event::AgentThinking { id } => {
                self.set_thinking(id);
                self.ensure_turn_complete_last();
            }
            Event::AgentThoughtDone { id } => {
                self.add_thought(id);
                self.ensure_turn_complete_last();
            }
            Event::AgentToolStart { id, name } => {
                self.start_tool(id, name);
                self.ensure_turn_complete_last();
            }
            Event::AgentToolEnd { duration_secs, output } => {
                self.end_tool(duration_secs, output);
                self.ensure_turn_complete_last();
            }
            Event::AgentResponse { id, content } => {
                self.append_response(id, content);
                self.ensure_turn_complete_last();
            }
            Event::AgentTurnComplete { id, duration_secs } => {
                self.complete_turn(id, duration_secs);
                self.ensure_turn_complete_last();
            }
            Event::AgentDone { id } => self.finish_turn(id),
            Event::AgentError { id, message } => {
                self.add_error(id, message);
                self.ensure_turn_complete_last();
            }
            Event::SwitchModel { provider, model } => self.switch_model(provider, model),
            Event::FollowUp => self.queue_follow_up(),
            Event::Abort => self.abort_queue(),
            Event::SpawnAgent => {}
            Event::ToggleExpand => self.toggle_expand_all(),
        }
    }

    fn toggle_expand_all(&mut self) {
        self.all_collapsed = !self.all_collapsed;
        self.messages_changed();
    }

    fn switch_model(&mut self, provider: String, model: String) {
        self.current_provider = provider.clone();
        self.current_model = model.clone();
        self.add_system_msg(format!("Switched to {}/{}", provider, model));
    }

    pub fn peek_queue(&self) -> Option<&(String, String)> {
        self.request_queue.front()
    }

    pub fn pop_queue(&mut self) -> Option<(String, String)> {
        self.request_queue.pop_front()
    }

    fn add_system_msg(&mut self, content: String) {
        self.messages.push(ChatMessage {
            role: Role::System,
            content,
            timestamp: now(),
            id: "system".to_string(),
        });
        self.messages_changed();
    }

    /// Move TurnComplete to the end of messages and bump its timestamp.
    /// Called after every agent event to ensure TurnComplete remains last.
    fn ensure_turn_complete_last(&mut self) {
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::TurnComplete) {
            let mut tc = self.messages.remove(idx);
            tc.timestamp = now();
            self.messages.push(tc);
            self.messages_changed();
        }
    }
}

//! Tests for input cursor movement (Emacs-style hotkeys)

#[cfg(test)]
mod tests {
    use crate::model::AppState;
    use crate::event::Event;

    #[test]
    fn cursor_starts_at_zero() {
        let state = AppState::default();
        assert_eq!(state.cursor_pos, 0);
    }

    #[test]
    fn insert_char_moves_cursor_forward() {
        let mut state = AppState::default();
        state.update(Event::Input('h'));
        state.update(Event::Input('i'));
        assert_eq!(state.input, "hi");
        assert_eq!(state.cursor_pos, 2);
    }

    #[test]
    fn cursor_left_moves_cursor_back() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::Input('b'));
        state.update(Event::CursorLeft);
        assert_eq!(state.cursor_pos, 1);
    }

    #[test]
    fn cursor_left_at_start_does_nothing() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::CursorLeft);
        state.update(Event::CursorLeft);
        assert_eq!(state.cursor_pos, 0);
    }

    #[test]
    fn cursor_right_moves_cursor_forward() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::CursorLeft);
        state.update(Event::CursorRight);
        assert_eq!(state.cursor_pos, 1);
    }

    #[test]
    fn cursor_right_at_end_does_nothing() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::CursorRight);
        assert_eq!(state.cursor_pos, 1);
    }

    #[test]
    fn cursor_start_moves_to_beginning() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::Input('b'));
        state.update(Event::Input('c'));
        state.update(Event::CursorStart);
        assert_eq!(state.cursor_pos, 0);
    }

    #[test]
    fn cursor_end_moves_to_end() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::Input('b'));
        state.update(Event::Input('c'));
        state.update(Event::CursorLeft);
        state.update(Event::CursorLeft);
        state.update(Event::CursorEnd);
        assert_eq!(state.cursor_pos, 3);
    }

    #[test]
    fn backspace_deletes_before_cursor_and_moves_left() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::Input('b'));
        state.update(Event::CursorLeft);
        state.update(Event::Backspace);
        // Deleted 'a', cursor moves left
        assert_eq!(state.input, "b");
        assert_eq!(state.cursor_pos, 0);
    }

    #[test]
    fn backspace_at_start_does_nothing() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::CursorStart);
        state.update(Event::Backspace);
        assert_eq!(state.input, "a");
        assert_eq!(state.cursor_pos, 0);
    }

    #[test]
    fn delete_word_removes_word_before_cursor() {
        let mut state = AppState::default();
        // Type "hello world"
        for c in "hello world".chars() {
            state.update(Event::Input(c));
        }
        // Move to end
        state.update(Event::CursorEnd);
        // Delete word (Emacs: deletes previous word "world")
        state.update(Event::DeleteWord);
        assert_eq!(state.input, "hello ");
        assert_eq!(state.cursor_pos, 6);
    }

    #[test]
    fn delete_word_at_middle_of_word() {
        let mut state = AppState::default();
        // Type "hello world"
        for c in "hello world".chars() {
            state.update(Event::Input(c));
        }
        // Move to position 8 (before 'r' in "world")
        state.update(Event::CursorEnd); // at 11
        state.update(Event::CursorLeft); // at 10
        state.update(Event::CursorLeft); // at 9
        state.update(Event::CursorLeft); // at 8 (before 'r')
        // DeleteWord should delete from position 6 ("w") to cursor 8 = "wo"
        state.update(Event::DeleteWord);
        assert_eq!(state.input, "hello rld");
        assert_eq!(state.cursor_pos, 6);
    }

    #[test]
    fn delete_to_end_removes_from_cursor_to_end() {
        let mut state = AppState::default();
        state.update(Event::Input('h'));
        state.update(Event::Input('e'));
        state.update(Event::Input('l'));
        state.update(Event::Input('l'));
        state.update(Event::Input('o'));
        // Move cursor left 3 times to position 2 (after "he")
        state.update(Event::CursorLeft);
        state.update(Event::CursorLeft);
        state.update(Event::CursorLeft);
        state.update(Event::DeleteToEnd);
        // Should delete "llo", leaving "he"
        assert_eq!(state.input, "he");
        assert_eq!(state.cursor_pos, 2);
    }

    #[test]
    fn delete_to_start_removes_from_start_to_cursor() {
        let mut state = AppState::default();
        state.update(Event::Input('h'));
        state.update(Event::Input('e'));
        state.update(Event::Input('l'));
        state.update(Event::Input('l'));
        state.update(Event::Input('o'));
        // Move cursor to middle
        state.update(Event::CursorEnd);
        state.update(Event::CursorLeft);
        state.update(Event::CursorLeft);
        state.update(Event::DeleteToStart);
        // Should delete "he", leaving "lo"
        assert_eq!(state.input, "lo");
        assert_eq!(state.cursor_pos, 0);
    }

    #[test]
    fn kill_char_removes_char_after_cursor() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::Input('b'));
        state.update(Event::Input('c'));
        // Cursor at end, KillChar is no-op
        state.update(Event::KillChar);
        assert_eq!(state.input, "abc");
        // Move cursor left twice (between 'a' and 'b')
        state.update(Event::CursorLeft);
        state.update(Event::CursorLeft);
        // KillChar deletes 'b' (char after cursor)
        state.update(Event::KillChar);
        assert_eq!(state.input, "ac");
        assert_eq!(state.cursor_pos, 1);
    }

    #[test]
    fn kill_char_at_end_does_nothing() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::KillChar);
        assert_eq!(state.input, "a");
        assert_eq!(state.cursor_pos, 1);
    }

    #[test]
    fn submit_clears_input_and_resets_cursor() {
        let mut state = AppState::default();
        state.update(Event::Input('t'));
        state.update(Event::Input('e'));
        state.update(Event::Input('s'));
        state.update(Event::Input('t'));
        assert_eq!(state.input, "test");
        assert_eq!(state.cursor_pos, 4);
        state.update(Event::Submit);
        assert!(state.input.is_empty());
        assert_eq!(state.cursor_pos, 0);
    }

    #[test]
    fn insert_char_at_middle_position() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::Input('c'));
        state.update(Event::CursorLeft);
        state.update(Event::Input('b'));
        assert_eq!(state.input, "abc");
        assert_eq!(state.cursor_pos, 2);
    }
}

//! Tests for grapheme-aware cursor movement

#[cfg(test)]
mod tests {
    use crate::model::AppState;
    use crate::event::Event;

    #[test]
    fn cursor_moves_by_grapheme_not_byte() {
        let mut state = AppState::default();
        // "é" is 2 bytes but 1 grapheme
        state.update(Event::Input('é'));
        assert_eq!(state.input, "é");
        assert_eq!(state.cursor_pos, 2); // byte position after 'é'
        state.update(Event::CursorLeft);
        assert_eq!(state.cursor_pos, 0); // should go to start, not 1
    }

    #[test]
    fn cursor_right_over_multi_byte_char() {
        let mut state = AppState::default();
        state.update(Event::Input('é'));
        state.update(Event::Input('a'));
        state.cursor_pos = 0;
        state.update(Event::CursorRight);
        assert_eq!(state.cursor_pos, 2); // skip full 'é' grapheme
    }

    #[test]
    fn delete_before_removes_full_grapheme() {
        let mut state = AppState::default();
        state.update(Event::Input('é'));
        state.update(Event::Backspace);
        assert_eq!(state.input, "");
        assert_eq!(state.cursor_pos, 0);
    }

    #[test]
    fn kill_char_removes_full_grapheme() {
        let mut state = AppState::default();
        state.update(Event::Input('é'));
        state.update(Event::Input('a'));
        state.cursor_pos = 0;
        state.update(Event::KillChar);
        assert_eq!(state.input, "a");
        assert_eq!(state.cursor_pos, 0);
    }

    #[test]
    fn emoji_is_one_grapheme() {
        let mut state = AppState::default();
        // "🎉" is 4 bytes
        state.update(Event::Input('🎉'));
        assert_eq!(state.cursor_pos, 4);
        state.update(Event::CursorLeft);
        assert_eq!(state.cursor_pos, 0);
    }

    #[test]
    fn mixed_ascii_and_unicode() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::Input('é'));
        state.update(Event::Input('b'));
        assert_eq!(state.cursor_pos, 4); // 1 + 2 + 1
        state.update(Event::CursorLeft);
        assert_eq!(state.cursor_pos, 3); // before 'b', after 'é'
        state.update(Event::CursorLeft);
        assert_eq!(state.cursor_pos, 1); // before 'é', after 'a'
        state.update(Event::CursorLeft);
        assert_eq!(state.cursor_pos, 0);
    }

    #[test]
    fn insert_newline_at_end() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::Input('b'));
        state.update(Event::Newline);
        state.update(Event::Input('c'));
        assert_eq!(state.input, "ab\nc");
        assert_eq!(state.cursor_pos, 4);
    }

    #[test]
    fn insert_newline_in_middle() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::Input('b'));
        state.update(Event::Input('c'));
        state.cursor_pos = 1; // after 'a'
        state.update(Event::Newline);
        assert_eq!(state.input, "a\nbc");
        assert_eq!(state.cursor_pos, 2);
    }

    #[test]
    fn multiline_input_supported() {
        let mut state = AppState::default();
        state.update(Event::Input('f'));
        state.update(Event::Input('i'));
        state.update(Event::Input('r'));
        state.update(Event::Input('s'));
        state.update(Event::Input('t'));
        state.update(Event::Newline);
        state.update(Event::Input('l'));
        state.update(Event::Input('i'));
        state.update(Event::Input('n'));
        state.update(Event::Input('e'));
        assert_eq!(state.input, "first\nline");
    }

    #[test]
    fn backspace_at_line_start_removes_newline() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::Newline);
        state.update(Event::Input('b'));
        // Now at end of "a\nb" (cursor after 'b')
        assert_eq!(state.input, "a\nb");
        assert_eq!(state.cursor_pos, 3); // After 'a\n' (2 chars) + 'b' (1 char)
        // Move cursor back to after the newline (start of second line)
        state.update(Event::CursorLeft);
        assert_eq!(state.cursor_pos, 2); // After 'a\n'
        // Backspace should remove the newline and join lines
        state.update(Event::Backspace);
        assert_eq!(state.input, "ab");
        assert_eq!(state.cursor_pos, 1); // Cursor at position 1 (after removing newline and 'a')
    }

    #[test]
    fn backspace_at_first_line_start_flashes() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::CursorLeft);
        assert_eq!(state.cursor_pos, 0);
        state.update(Event::Backspace);
        // Should flash, not delete
        assert_eq!(state.input, "a");
        assert!(state.input_flash > 0);
    }

    #[test]
    fn backspace_removes_only_first_newline() {
        let mut state = AppState::default();
        state.update(Event::Input('a'));
        state.update(Event::Newline);
        state.update(Event::Input('b'));
        state.update(Event::Newline);
        state.update(Event::Input('c'));
        assert_eq!(state.input, "a\nb\nc");
        // Cursor is at end (after 'c')
        // Move to start of third line
        state.cursor_pos = 4;
        state.update(Event::Backspace);
        // Should only remove the newline before 'c', not the one before 'b'
        assert_eq!(state.input, "a\nbc");
    }

    #[test]
    fn bash_prefix_runs_command() {
        let mut state = AppState::default();
        state.update(Event::Input('!'));
        state.update(Event::Input('e'));
        state.update(Event::Input('c'));
        state.update(Event::Input('h'));
        state.update(Event::Input('o'));
        state.update(Event::Input(' '));
        state.update(Event::Input('h'));
        state.update(Event::Input('e'));
        state.update(Event::Input('l'));
        state.update(Event::Input('l'));
        state.update(Event::Input('o'));
        state.update(Event::Submit);
        // Command should have run and added output
        assert!(state.messages.iter().any(|m| m.content.contains("hello")),
            "Should have hello in output");
    }

    #[test]
    fn bash_prefix_not_sent_to_agent() {
        let mut state = AppState::default();
        state.update(Event::Input('!'));
        state.update(Event::Input('p'));
        state.update(Event::Input('w'));
        state.update(Event::Input('d'));
        state.update(Event::Submit);
        // Should not add to request queue
        assert!(state.request_queue.is_empty(), "Bash command should not be queued for agent");
    }

    #[test]
    fn regular_submit_still_works() {
        let mut state = AppState::default();
        state.update(Event::Input('h'));
        state.update(Event::Input('e'));
        state.update(Event::Input('l'));
        state.update(Event::Input('l'));
        state.update(Event::Input('o'));
        state.update(Event::Submit);
        // Should add user message and queue for agent
        assert!(!state.request_queue.is_empty(), "Regular submit should queue for agent");
        assert_eq!(state.messages.len(), 1, "Should have one message");
    }
}

