//! ConfigAgent — Watches config files for changes and emits ConfigChanged events
//!
//! The ConfigAgent monitors the configuration file and emits domain events
//! when changes are detected, allowing actors to apply new settings
//! without requiring a restart.

use std::collections::HashMap;
use std::fs;
use std::path::PathBuf;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::time::{Duration, SystemTime};

use crate::event_bus::{ActorChannel, BusEventEnvelope, ConfigValue, DomainEvent, EventBus};

/// Config file state for change detection
#[derive(Debug, Clone)]
struct ConfigFileState {
    path: PathBuf,
    last_mtime: Option<u64>,
    last_hash: Option<u64>,
}

impl ConfigFileState {
    fn new(path: PathBuf) -> Self {
        Self {
            path,
            last_mtime: None,
            last_hash: None,
        }
    }

    /// Check if file has changed and update state
    fn check_and_update(&mut self) -> Option<HashMap<String, ConfigValue>> {
        let metadata = match fs::metadata(&self.path) {
            Ok(m) => m,
            Err(_) => return None,
        };

        let mtime = metadata.modified().ok()?;
        let mtime_nanos = mtime
            .duration_since(SystemTime::UNIX_EPOCH)
            .ok()?
            .as_nanos() as u64;

        // Check if modified time changed
        let time_changed = self.last_mtime.map(|t| t != mtime_nanos).unwrap_or(true);

        // Calculate content hash
        let content = fs::read(&self.path).ok()?;
        let content_hash = simple_hash(&content);

        // Check if content changed
        let content_changed = self.last_hash.map(|h| h != content_hash).unwrap_or(true);

        if time_changed || content_changed {
            self.last_mtime = Some(mtime_nanos);
            self.last_hash = Some(content_hash);

            // Parse the config
            let content_str = String::from_utf8_lossy(&content);
            let value: toml::Value = toml::from_str(&content_str).ok()?;
            self.parse_config(&value)
        } else {
            None
        }
    }

    fn parse_config(&self, value: &toml::Value) -> Option<HashMap<String, ConfigValue>> {
        if let toml::Value::Table(table) = value {
            let mut changes = HashMap::new();
            for (key, val) in table {
                changes.insert(key.clone(), ConfigValue::from_toml(val));
            }
            Some(changes)
        } else {
            None
        }
    }
}

/// Simple hash function for content change detection
fn simple_hash(data: &[u8]) -> u64 {
    use std::collections::hash_map::DefaultHasher;
    use std::hash::{Hash, Hasher};
    let mut hasher = DefaultHasher::new();
    data.hash(&mut hasher);
    hasher.finish()
}

/// Run the ConfigAgent actor loop.
///
/// The actor:
/// - Monitors config files for changes
/// - Parses TOML configuration
/// - Emits ConfigChanged events on modification
pub fn run_config_agent(
    bus: EventBus,
    _channel: ActorChannel<BusEventEnvelope>,
    shutdown: Arc<AtomicBool>,
    config_paths: Vec<PathBuf>,
    poll_interval: Duration,
) {
    let mut states: Vec<ConfigFileState> = config_paths.into_iter().map(ConfigFileState::new).collect();

    while !shutdown.load(Ordering::SeqCst) {
        for state in &mut states {
            if let Some(changes) = state.check_and_update() {
                bus.publish_domain(DomainEvent::ConfigChanged {
                    path: state.path.clone(),
                    changes,
                });
            }
        }

        std::thread::sleep(poll_interval);
    }
}

/// Parse a TOML configuration file and return as HashMap
pub fn parse_config(path: &PathBuf) -> anyhow::Result<HashMap<String, ConfigValue>> {
    let content = fs::read_to_string(path)?;
    let value: toml::Value = toml::from_str(&content)?;
    let table = value.as_table().ok_or_else(|| {
        anyhow::anyhow!("Config file must contain a table at root")
    })?;

    let mut config = HashMap::new();
    for (key, val) in table {
        config.insert(key.clone(), ConfigValue::from_toml(val));
    }
    Ok(config)
}

/// Get a string config value
pub fn get_string(config: &HashMap<String, ConfigValue>, key: &str) -> Option<String> {
    config.get(key).and_then(|v| match v {
        ConfigValue::String(s) => Some(s.clone()),
        _ => None,
    })
}

/// Get a boolean config value
pub fn get_bool(config: &HashMap<String, ConfigValue>, key: &str) -> Option<bool> {
    config.get(key).and_then(|v| match v {
        ConfigValue::Boolean(b) => Some(*b),
        _ => None,
    })
}

/// Get an integer config value
pub fn get_integer(config: &HashMap<String, ConfigValue>, key: &str) -> Option<i64> {
    config.get(key).and_then(|v| match v {
        ConfigValue::Integer(i) => Some(*i),
        _ => None,
    })
}

/// Get a nested config value (dot-separated path)
pub fn get_nested(config: &HashMap<String, ConfigValue>, path: &str) -> Option<ConfigValue> {
    let parts: Vec<&str> = path.split('.').collect();
    let mut current = config.clone();

    for (i, part) in parts.iter().enumerate() {
        if i == parts.len() - 1 {
            return current.get(*part).cloned();
        }

        match current.get(*part)? {
            ConfigValue::Object(map) => current = map.clone(),
            _ => return None,
        }
    }
    None
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn simple_hash_deterministic() {
        let data = b"hello world";
        let hash1 = simple_hash(data);
        let hash2 = simple_hash(data);
        assert_eq!(hash1, hash2);
    }

    #[test]
    fn simple_hash_different_content() {
        let hash1 = simple_hash(b"hello");
        let hash2 = simple_hash(b"world");
        assert_ne!(hash1, hash2);
    }

    #[test]
    fn get_string_helper() {
        let mut config = HashMap::new();
        config.insert("name".to_string(), ConfigValue::String("test".to_string()));
        config.insert("count".to_string(), ConfigValue::Integer(5));

        assert_eq!(get_string(&config, "name"), Some("test".to_string()));
        assert_eq!(get_string(&config, "count"), None);
        assert_eq!(get_string(&config, "missing"), None);
    }

    #[test]
    fn get_bool_helper() {
        let mut config = HashMap::new();
        config.insert("enabled".to_string(), ConfigValue::Boolean(true));
        config.insert("name".to_string(), ConfigValue::String("test".to_string()));

        assert_eq!(get_bool(&config, "enabled"), Some(true));
        assert_eq!(get_bool(&config, "name"), None);
    }

    #[test]
    fn get_integer_helper() {
        let mut config = HashMap::new();
        config.insert("count".to_string(), ConfigValue::Integer(42));

        assert_eq!(get_integer(&config, "count"), Some(42));
        assert_eq!(get_integer(&config, "missing"), None);
    }

    #[test]
    fn get_nested_helper() {
        let mut inner = HashMap::new();
        inner.insert("value".to_string(), ConfigValue::String("nested".to_string()));

        let mut config = HashMap::new();
        config.insert("outer".to_string(), ConfigValue::Object(inner));

        let result = get_nested(&config, "outer.value");
        assert!(matches!(result, Some(ConfigValue::String(s)) if s == "nested"));
    }

    #[test]
    fn get_nested_deep_path() {
        let mut level2 = HashMap::new();
        level2.insert("key".to_string(), ConfigValue::Integer(123));

        let mut level1 = HashMap::new();
        level1.insert("inner".to_string(), ConfigValue::Object(level2));

        let mut config = HashMap::new();
        config.insert("outer".to_string(), ConfigValue::Object(level1));

        let result = get_nested(&config, "outer.inner.key");
        assert!(matches!(result, Some(ConfigValue::Integer(123))));
    }

    #[test]
    fn config_file_state_detects_change() {
        let temp_dir = std::env::temp_dir().join("runie_config_test");
        std::fs::create_dir_all(&temp_dir).ok();
        let config_path = temp_dir.join("config.toml");

        // Write initial config
        std::fs::write(&config_path, "key = \"value\"\n").unwrap();
        std::thread::sleep(Duration::from_millis(10));

        let mut state = ConfigFileState::new(config_path.clone());

        // First check should return changes
        let changes = state.check_and_update();
        assert!(changes.is_some());

        // Second check should return None (no change)
        let changes = state.check_and_update();
        assert!(changes.is_none());

        // Modify the file
        std::fs::write(&config_path, "key = \"new_value\"\n").unwrap();
        std::thread::sleep(Duration::from_millis(10));

        // Should detect change
        let changes = state.check_and_update();
        assert!(changes.is_some());

        let _ = std::fs::remove_dir_all(temp_dir);
    }

    #[test]
    fn parse_config_file() {
        let temp_dir = std::env::temp_dir().join("runie_parse_test");
        std::fs::create_dir_all(&temp_dir).ok();
        let config_path = temp_dir.join("config.toml");

        std::fs::write(
            &config_path,
            r#"
name = "runie"
max_tokens = 4096
enabled = true
"#,
        )
        .unwrap();

        let config = parse_config(&config_path).unwrap();
        assert_eq!(get_string(&config, "name"), Some("runie".to_string()));
        assert_eq!(get_integer(&config, "max_tokens"), Some(4096));
        assert_eq!(get_bool(&config, "enabled"), Some(true));

        let _ = std::fs::remove_dir_all(temp_dir);
    }
}

//! Runie Terminal — Non-blocking event loop with render actor
//!
//! Architecture (impossible to block by design):
//!   1. Event loop: single-threaded async, only async ops
//!   2. State: owned by event loop, mutable borrow per event
//!   3. Snapshot: immutable frame description (the UI DSL)
//!   4. Render actor: owns Terminal, receives Snapshots via channel
//!   5. If render is slow, old Snapshots are dropped — event loop never waits

use crossterm::event::{Event, EventStream, KeyCode, KeyEvent, KeyEventKind, KeyModifiers};
use futures::StreamExt;
use ratatui::{backend::CrosstermBackend, Terminal};
use runie_agent::{AgentCommand, run_agent_turn};
use runie_core::{AppState, Event as CoreEvent, Snapshot};
use std::{io, time::Duration};
use tokio::sync::mpsc;

const ANIM_MS: u64 = 200;

struct Cleanup;

impl Drop for Cleanup {
    fn drop(&mut self) {
        let _ = crossterm::execute!(std::io::stdout(), crossterm::terminal::LeaveAlternateScreen);
        let _ = crossterm::terminal::disable_raw_mode();
    }
}

#[tokio::main(flavor = "multi_thread", worker_threads = 2)]
async fn main() -> io::Result<()> {
    let _cleanup = Cleanup;
    let terminal = setup_terminal()?;
    let state = AppState::default();

    let (input_tx, input_rx) = mpsc::channel::<CoreEvent>(100);
    let (agent_tx, agent_rx) = mpsc::channel::<CoreEvent>(100);
    let (cmd_tx, cmd_rx) = mpsc::channel::<AgentCommand>(10);
    let (render_tx, render_rx) = mpsc::channel::<Snapshot>(1);

    tokio::spawn(agent_loop(cmd_rx, agent_tx));
    tokio::spawn(input_reader(input_tx));
    tokio::spawn(render_task(terminal, render_rx));

    event_loop(state, input_rx, agent_rx, cmd_tx, render_tx).await
}

fn setup_terminal() -> io::Result<Terminal<CrosstermBackend<std::io::Stdout>>> {
    crossterm::terminal::enable_raw_mode()?;
    crossterm::execute!(
        std::io::stdout(),
        crossterm::terminal::EnterAlternateScreen,
        crossterm::event::EnableBracketedPaste,
    )?;
    Terminal::new(CrosstermBackend::new(std::io::stdout()))
}

async fn render_task(
    mut terminal: Terminal<CrosstermBackend<std::io::Stdout>>,
    mut render_rx: mpsc::Receiver<Snapshot>,
) {
    while let Some(snap) = render_rx.recv().await {
        let _ = terminal.draw(|f| runie_tui::ui::draw_snapshot(f, &snap));
    }
}

async fn input_reader(input_tx: mpsc::Sender<CoreEvent>) {
    let mut reader = EventStream::new();
    while let Some(Ok(event)) = reader.next().await {
        if let Some(evt) = convert_event(&event) {
            let is_quit = matches!(&evt, CoreEvent::Quit | CoreEvent::Reset);
            if input_tx.send(evt).await.is_err() { break; }
            if is_quit { break; }
        }
    }
}

async fn event_loop(
    mut state: AppState,
    mut input_rx: mpsc::Receiver<CoreEvent>,
    mut agent_rx: mpsc::Receiver<CoreEvent>,
    cmd_tx: mpsc::Sender<AgentCommand>,
    render_tx: mpsc::Sender<Snapshot>,
) -> io::Result<()> {
    let mut anim = tokio::time::interval(Duration::from_millis(ANIM_MS));

    // Initial draw so the user sees the app immediately, without waiting
    // for the first keyboard event.
    state.ensure_fresh();
    let _ = render_tx.try_send(state.snapshot());

    loop {
        tokio::select! {
            biased;

            Some(evt) = input_rx.recv() => {
                let was_submit = matches!(evt, CoreEvent::Submit);
                let was_followup = matches!(evt, CoreEvent::FollowUp);
                let was_quit = matches!(evt, CoreEvent::Quit | CoreEvent::Reset);
                state.update(evt);
                if was_submit || was_followup {
                    spawn_if_queued(&mut state, &cmd_tx).await;
                }
                if was_quit {
                    return Ok(());
                }
            }

            Some(evt) = agent_rx.recv() => {
                let was_done = matches!(evt, CoreEvent::AgentDone { .. } | CoreEvent::AgentError { .. });
                state.update(evt);
                if was_done {
                    spawn_if_queued(&mut state, &cmd_tx).await;
                }
            }

            _ = anim.tick() => {
                state.tick_animation();
            }
        }

        state.ensure_fresh();
        let snap = state.snapshot();
        if render_tx.try_send(snap).is_err() {
            // Render task is behind — old snapshot dropped, latest will draw
        }
    }
}

async fn agent_loop(mut cmd_rx: mpsc::Receiver<AgentCommand>, agent_tx: mpsc::Sender<CoreEvent>) {
    while let Some(cmd) = cmd_rx.recv().await {
        let agent_tx_clone = agent_tx.clone();
        let cmd_id = cmd.id.clone();

        let result = run_agent_turn(
            &cmd,
            |evt| {
                let tx = agent_tx_clone.clone();
                let _ = tx.try_send(evt);
            },
            5,
        ).await;

        if let Err(e) = result {
            let _ = agent_tx.send(CoreEvent::AgentError {
                id: cmd_id,
                message: format!("Agent error: {}", e),
            }).await;
        }
    }
}

async fn spawn_if_queued(state: &mut AppState, cmd_tx: &mpsc::Sender<AgentCommand>) {
    if let Some((content, id)) = state.peek_queue() {
        let content = content.clone();
        let id = id.clone();
        state.pop_queue();
        state.streaming = true;
        state.turn_active = true;
        state.inflight += 1;
        let _ = cmd_tx.send(AgentCommand {
            content,
            id,
            provider: state.current_provider.clone(),
            model: state.current_model.clone(),
        }).await;
    }
}

#[cfg(test)]
mod tests {
    use crossterm::event::{KeyCode, KeyEvent, KeyModifiers, KeyEventKind};

    #[test]
    fn animation_interval_is_200ms() {
        assert_eq!(super::ANIM_MS, 200, "ANIM_MS must be 200ms for visible braille spinner, got {}", super::ANIM_MS);
    }

    #[test]
    fn ctrl_shift_e_converts_to_toggle_expand() {
        let key = KeyEvent::new(KeyCode::Char('E'), KeyModifiers::CONTROL | KeyModifiers::SHIFT);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::ToggleExpand)), "Ctrl+Shift+E should map to ToggleExpand, got {:?}", result);
    }

    #[test]
    fn ctrl_e_converts_to_toggle_expand_for_terminals_without_shift() {
        let key = KeyEvent::new(KeyCode::Char('e'), KeyModifiers::CONTROL);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::ToggleExpand)), "Ctrl+E should map to ToggleExpand (terminal fallback), got {:?}", result);
    }

    #[test]
    fn ctrl_c_converts_to_quit() {
        let key = KeyEvent::new(KeyCode::Char('c'), KeyModifiers::CONTROL);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::Quit)), "Ctrl+C should map to Quit");
    }

    #[test]
    fn plain_e_not_converted() {
        let key = KeyEvent::new(KeyCode::Char('e'), KeyModifiers::empty());
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::Input('e'))), "Plain e should map to Input");
    }

    #[test]
    fn ctrl_e_does_not_conflict_with_quit() {
        let key = KeyEvent::new(KeyCode::Char('e'), KeyModifiers::CONTROL);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(!matches!(result, Some(super::CoreEvent::Quit)), "Ctrl+E should NOT map to Quit");
    }

    #[tokio::test]
    async fn spawn_if_queued_sets_turn_active_and_inflight() {
        let (tx, mut rx) = tokio::sync::mpsc::channel::<super::AgentCommand>(10);
        let mut state = super::AppState::default();
        state.request_queue.push_back(("hello".to_string(), "req.0".to_string()));

        assert!(!state.turn_active);
        assert_eq!(state.inflight, 0);

        super::spawn_if_queued(&mut state, &tx).await;

        assert!(state.turn_active, "spawn_if_queued must set turn_active");
        assert_eq!(state.inflight, 1, "spawn_if_queued must increment inflight");
        assert!(state.request_queue.is_empty(), "Message should be popped from request_queue");

        let cmd = rx.try_recv().expect("Command should be sent to agent");
        assert_eq!(cmd.content, "hello");
    }

    #[tokio::test]
    async fn spawn_if_queued_noop_when_queue_empty() {
        let (tx, _rx) = tokio::sync::mpsc::channel::<super::AgentCommand>(10);
        let mut state = super::AppState::default();

        super::spawn_if_queued(&mut state, &tx).await;

        assert!(!state.turn_active);
        assert_eq!(state.inflight, 0);
    }

    #[test]
    fn ctrl_shift_e_on_repeat_kind_still_works() {
        let key = KeyEvent::new_with_kind(KeyCode::Char('E'), KeyModifiers::CONTROL | KeyModifiers::SHIFT, KeyEventKind::Repeat);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::ToggleExpand)), "Ctrl+Shift+E with Repeat kind should still map to ToggleExpand, got {:?}", result);
    }

    #[test]
    fn ctrl_e_on_repeat_kind_still_works() {
        let key = KeyEvent::new_with_kind(KeyCode::Char('e'), KeyModifiers::CONTROL, KeyEventKind::Repeat);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::ToggleExpand)), "Ctrl+E with Repeat kind should still map to ToggleExpand, got {:?}", result);
    }

    #[test]
    fn ctrl_z_converts_to_undo() {
        let key = KeyEvent::new(KeyCode::Char('z'), KeyModifiers::CONTROL);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::Undo)), "Ctrl+Z should map to Undo");
    }

    #[test]
    fn ctrl_y_converts_to_redo() {
        let key = KeyEvent::new(KeyCode::Char('y'), KeyModifiers::CONTROL);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::Redo)), "Ctrl+Y should map to Redo");
    }

    #[test]
    fn alt_b_converts_to_word_left() {
        let key = KeyEvent::new(KeyCode::Char('b'), KeyModifiers::ALT);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::CursorWordLeft)), "Alt+B should map to CursorWordLeft");
    }

    #[test]
    fn alt_f_converts_to_word_right() {
        let key = KeyEvent::new(KeyCode::Char('f'), KeyModifiers::ALT);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::CursorWordRight)), "Alt+F should map to CursorWordRight");
    }

    #[test]
    fn bracketed_paste_converts_to_paste_event() {
        let event = crossterm::event::Event::Paste("hello world".to_string());
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::Paste(s)) if s == "hello world"), "Paste event should map to CoreEvent::Paste");
    }
}

fn convert_event(event: &Event) -> Option<CoreEvent> {
    log_key_event(event);
    match event {
        Event::Paste(data) => {
            Some(CoreEvent::Paste(data.clone()))
        }
        Event::Key(key) if key.kind == KeyEventKind::Press || key.kind == KeyEventKind::Repeat => {
            map_key_event(key)
        }
        _ => None,
    }
}

fn log_key_event(event: &Event) {
    if let Event::Key(key) = event {
        if std::env::var("RUNIE_DEBUG").is_ok() {
            use std::io::Write;
            let _ = std::fs::OpenOptions::new()
                .create(true)
                .append(true)
                .open("/tmp/runie_keys.log")
                .and_then(|mut f| writeln!(f, "{:?}", key));
        }
    }
}

fn map_key_event(key: &KeyEvent) -> Option<CoreEvent> {
    if key.modifiers.contains(KeyModifiers::CONTROL) {
        map_ctrl_key(key.code)
    } else if key.modifiers.contains(KeyModifiers::ALT) {
        map_alt_key(key.code)
    } else if key.modifiers.contains(KeyModifiers::SHIFT) {
        map_shift_key(key.code)
    } else {
        map_plain_key(key.code)
    }
}

fn map_ctrl_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        // Ctrl+E: toggle expand (also Ctrl+Shift+E on terminals with proper modifier)
        KeyCode::Char('e') | KeyCode::Char('E') => Some(CoreEvent::ToggleExpand),
        // Ctrl+J: newline (line feed)
        KeyCode::Char('j') | KeyCode::Char('J') => Some(CoreEvent::Newline),
        // Ctrl+A: move cursor to start (Emacs)
        KeyCode::Char('a') | KeyCode::Char('A') => Some(CoreEvent::CursorStart),
        // Ctrl+B: move cursor backward (Emacs)
        KeyCode::Char('b') | KeyCode::Char('B') => Some(CoreEvent::CursorLeft),
        // Ctrl+F: move cursor forward (Emacs)
        KeyCode::Char('f') | KeyCode::Char('F') => Some(CoreEvent::CursorRight),
        // Ctrl+W: delete word (Emacs)
        KeyCode::Char('w') | KeyCode::Char('W') => Some(CoreEvent::DeleteWord),
        // Ctrl+K: delete to end (Emacs)
        KeyCode::Char('k') | KeyCode::Char('K') => Some(CoreEvent::DeleteToEnd),
        // Ctrl+U: delete to start (Emacs)
        KeyCode::Char('u') | KeyCode::Char('U') => Some(CoreEvent::DeleteToStart),
        // Ctrl+D: delete char at cursor (Emacs)
        KeyCode::Char('d') | KeyCode::Char('D') => Some(CoreEvent::KillChar),
        // Ctrl+Z: undo
        KeyCode::Char('z') | KeyCode::Char('Z') => Some(CoreEvent::Undo),
        // Ctrl+Y: redo
        KeyCode::Char('y') | KeyCode::Char('Y') => Some(CoreEvent::Redo),
        // Ctrl+C: quit
        KeyCode::Char('c') | KeyCode::Char('C') => Some(CoreEvent::Quit),
        // Ctrl+S: abort
        KeyCode::Char('s') | KeyCode::Char('S') => Some(CoreEvent::Abort),
        _ => None,
    }
}

fn map_alt_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        KeyCode::Enter => Some(CoreEvent::FollowUp),
        // Alt+B: word backward
        KeyCode::Char('b') | KeyCode::Char('B') => Some(CoreEvent::CursorWordLeft),
        // Alt+F: word forward
        KeyCode::Char('f') | KeyCode::Char('F') => Some(CoreEvent::CursorWordRight),
        _ => None,
    }
}

fn map_shift_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        // Shift+Enter: newline
        KeyCode::Enter => Some(CoreEvent::Newline),
        _ => None,
    }
}

fn map_plain_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        KeyCode::Esc => Some(CoreEvent::Abort),
        KeyCode::Char('\t') | KeyCode::Tab | KeyCode::BackTab => Some(CoreEvent::Input('\t')),
        KeyCode::Char(c) => Some(CoreEvent::Input(c)),
        KeyCode::Backspace => Some(CoreEvent::Backspace),
        KeyCode::Enter => Some(CoreEvent::Submit),
        KeyCode::Up => Some(CoreEvent::HistoryPrev),
        KeyCode::Down => Some(CoreEvent::HistoryNext),
        KeyCode::Left => Some(CoreEvent::CursorLeft),
        KeyCode::Right => Some(CoreEvent::CursorRight),
        KeyCode::Home => Some(CoreEvent::CursorStart),
        KeyCode::End => Some(CoreEvent::CursorEnd),
        KeyCode::Delete => Some(CoreEvent::KillChar),
        _ => None,
    }
}

